/**
 * Pure helpers for the News surfaces (tab + article view). Kept out of
 * the components so they can be unit-tested in isolation.
 */

/**
 * Whether a news post was meaningfully edited after publication. Only
 * RSS / webhook posts carry `upstreamUpdatedAt`; we treat a >1-minute
 * gap as a real edit (sub-minute deltas are ingest-pipeline noise).
 */
export function isNewsPostEdited(post: {
  publishedAt: string;
  upstreamUpdatedAt?: string | null;
}): boolean {
  if (!post.upstreamUpdatedAt) return false;
  const updated = Date.parse(post.upstreamUpdatedAt);
  const published = Date.parse(post.publishedAt);
  if (Number.isNaN(updated) || Number.isNaN(published)) return false;
  return updated > published + 60_000;
}

/** Compact relative time for the "edited Xh ago" badge. */
export function formatNewsEditedAgo(iso: string): string {
  const ts = Date.parse(iso);
  if (Number.isNaN(ts)) return "";
  const diffMs = Date.now() - ts;
  const m = Math.floor(diffMs / 60_000);
  if (m < 1) return "just now";
  if (m < 60) return `${m}m ago`;
  const h = Math.floor(m / 60);
  if (h < 24) return `${h}h ago`;
  const d = Math.floor(h / 24);
  if (d < 7) return `${d}d ago`;
  return new Date(ts).toLocaleDateString();
}
