"use client";

import type { LucideIcon } from "lucide-react";
import { cn } from "@/lib/utils";

interface IconProps extends React.SVGProps<SVGSVGElement> {
  /** A static `lucide-react` icon. Pass the component directly. */
  icon: LucideIcon;
  size?: number;
  /** Stroke weight — match Intercom's slightly chunky default. */
  strokeWidth?: number;
}

/**
 * Static icon wrapper. Standardises sizing + stroke across the
 * widget so we don't sprinkle `className="h-5 w-5"` on every call
 * site. Animated icons (send-success, heart-pop on reaction) come
 * from `lucide-animated` and are imported separately in the surfaces
 * that need them — those are intentional engagement moments, not
 * the default for every icon.
 */
export function Icon({
  icon: IconComp,
  size = 20,
  strokeWidth = 2,
  className,
  ...rest
}: IconProps) {
  return (
    <IconComp
      width={size}
      height={size}
      strokeWidth={strokeWidth}
      className={cn("shrink-0", className)}
      {...rest}
    />
  );
}
