"use client";

import { useEffect, useRef } from "react";

/**
 * Module-local scratchpad for list-view scroll positions. Keyed by a
 * caller-chosen tag (`"news"`, `"help"`) so each list keeps its own
 * value across list ↔ detail ↔ list navigation cycles.
 *
 * Lives at module scope (NOT React state) so list components can
 * unmount during route transitions without dropping the value — when
 * they re-mount, `useScrollRestore` rehydrates the recorded offset.
 */
const scrollPositions = new Map<string, number>();

/**
 * Wire a `ScrollArea` viewport ref to a named slot in the scratchpad.
 * Pass the resulting ref to `<ScrollArea viewportRef={…} />`.
 *
 * - On mount → restores the saved offset (if any) on the next frame
 *   so layout has settled before we set `scrollTop`.
 * - On scroll → writes the current offset to the slot.
 * - On unmount → leaves the last seen value intact for the next mount.
 *
 * Restoration waits for content to grow tall enough to honour the
 * saved offset — Apollo cache rehydration on the route transition can
 * paint the list initially empty, so a single `requestAnimationFrame`
 * isn't always enough. We poll for up to ~500 ms.
 */
export function useScrollRestore(key: string) {
  const viewportRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    const vp = viewportRef.current;
    if (!vp) return;
    const saved = scrollPositions.get(key) ?? 0;

    let cancelled = false;
    const start = performance.now();
    const tryRestore = () => {
      if (cancelled || !viewportRef.current) return;
      const el = viewportRef.current;
      // Only restore once the content is at least as tall as where
      // we want to scroll to — otherwise the browser clamps to the
      // current `scrollHeight - clientHeight` and we land short.
      if (el.scrollHeight - el.clientHeight >= saved) {
        el.scrollTop = saved;
        return;
      }
      if (performance.now() - start > 500) {
        // Content never grew tall enough — restore anyway so we land
        // wherever the clamp puts us instead of leaving the user at
        // the top of a half-loaded list.
        el.scrollTop = saved;
        return;
      }
      requestAnimationFrame(tryRestore);
    };
    requestAnimationFrame(tryRestore);

    const onScroll = () => {
      scrollPositions.set(key, vp.scrollTop);
    };
    vp.addEventListener("scroll", onScroll, { passive: true });
    return () => {
      cancelled = true;
      vp.removeEventListener("scroll", onScroll);
    };
  }, [key]);

  return viewportRef;
}

/**
 * Wipe a stored position — call when the list's identity changes
 * (e.g. operator switches integration in preview, locale change) so
 * the next mount starts from the top instead of restoring a stale
 * offset against a different dataset.
 */
export function clearScrollRestore(key: string) {
  scrollPositions.delete(key);
}
