"use client";

import { SearchIcon } from "@/components/widget/icons/animated";
import { cn } from "@/lib/utils";

/**
 * Sticky search field used by the Help + News tabs.
 *
 * The input is intentionally NOT a tonal pill — it fills the entire
 * header band edge-to-edge so the search affordance reads as part of
 * the tab's chrome, not as a card floating inside it. A hairline
 * bottom divider separates the band from the scrolling list below.
 *
 * Sticky positioning relies on the parent being a flex column whose
 * scrollable child contains this header — `position: sticky; top: 0`
 * inside a scroll viewport keeps it pinned as the list scrolls. The
 * search icon sits absolutely positioned over the input's left
 * padding so the input itself stays a single flat surface.
 */
export function StickySearchHeader({
  value,
  onChange,
  placeholder,
  className,
}: {
  value: string;
  onChange: (next: string) => void;
  placeholder: string;
  className?: string;
}) {
  return (
    <div className={cn("sticky top-0 z-10 border-wx-border border-b bg-wx-bg", className)}>
      <span className="-translate-y-1/2 pointer-events-none absolute top-1/2 left-4 text-wx-fg-muted">
        <SearchIcon size={16} />
      </span>
      <input
        type="search"
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        // Edge-to-edge, no border, transparent — the band's bottom
        // divider IS the visual separator. Compact py-3 height; pl-10
        // clears the search icon. Suppress the browser's "search"
        // cancel-x glyph (we don't need it; the visitor just clears
        // the field by erasing).
        className={cn(
          "block w-full border-0 bg-transparent px-4 py-3 pl-10 text-sm text-wx-fg",
          "placeholder:text-wx-fg-muted focus:outline-none focus:ring-0",
          "[&::-webkit-search-cancel-button]:appearance-none",
        )}
      />
    </div>
  );
}
