"use client";

import { Megaphone } from "lucide-react";
import { motion } from "motion/react";
import { useLocale, useTranslations } from "next-intl";
import { useCallback, useEffect, useMemo, useState } from "react";
import { CardSubtitle, CardTitle } from "@/components/ui/card";
import { Icon } from "@/components/ui/icon";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Skeleton } from "@/components/ui/skeleton";
import { AuthorAvatars, toAuthorChips } from "@/components/widget/author-avatars";
import { StickySearchHeader } from "@/components/widget/sticky-search-header";
import { getMockNewsItems, type MockNewsItem } from "@/dummy";
import { useVisitorNewsListQuery } from "@/lib/graphql/queries/generated/news.generated";
import { useScrollRestore } from "@/lib/use-scroll-restore";
import { useWidgetEnv } from "@/lib/use-widget-env";
import { cn } from "@/lib/utils";
import { formatNewsEditedAgo, isNewsPostEdited } from "./helpers";

// Re-exported so `news-article-view` keeps importing from `./tabs/news-tab`.
export { formatNewsEditedAgo, isNewsPostEdited } from "./helpers";

const PAGE_SIZE = 10;
/** Trigger fetchMore (real mode) / unhide more (preview mode) when
 *  the visitor scrolls within this many pixels of the bottom. */
const LOAD_MORE_THRESHOLD = 240;

interface NewsTabProps {
  isDummy: boolean;
  /** Shell-driven drill-in. Tile click → opens the post detail. */
  onOpenArticle: (id: string) => void;
}

/**
 * News feed. Real path queries the consolidated `visitorNewsList`
 * which serves both the chronological feed and `$text`-ranked search
 * via the same args (pass `query` for search, omit for feed).
 * Returns `PaginatedNewsPosts` (`{ items, meta }`) — pagination uses
 * `meta.hasNextPage` + `offset` rather than a length heuristic.
 *
 * Dummy + preview modes share the in-memory MOCK list / prefetched
 * array and paginate locally; preview-mode search filters the
 * prefetched list client-side (no BE round-trip).
 */
export function NewsTab({ isDummy, onOpenArticle }: NewsTabProps) {
  const t = useTranslations("news");
  const tDemo = useTranslations("demo");
  const locale = useLocale();
  const env = useWidgetEnv();
  const [query, setQuery] = useState("");
  const debounced = useDebounced(query, 300);
  const isSearching = debounced.length >= 2;

  // Dashboard prefetch — when the dashboard preview pane mounted the
  // widget with `previewData.newsPosts`, render those instead of
  // round-tripping to the visitor surface.
  //
  // Important: only short-circuit when the prefetch actually carries
  // rows. The dashboard's `useMemo` always emits a (possibly empty)
  // array while its own query is in-flight; treating an empty array
  // as "use the prefetch" would skip the BE call and leave the tab
  // permanently empty. An empty prefetch falls through to the BE
  // query, which serves both the standalone-widget path and the
  // preview-still-loading edge case.
  const previewFeed = env.previewData?.newsPosts;
  const usePreview = !isDummy && Array.isArray(previewFeed) && previewFeed.length > 0;

  // `visibleCount` paginates the prefetched array in preview/dummy
  // modes. Real mode tracks page progress through Apollo's cache via
  // `fetchMore`.
  const [visibleCount, setVisibleCount] = useState(PAGE_SIZE);

  const {
    data: listData,
    error: listError,
    loading: listLoading,
    fetchMore,
  } = useVisitorNewsListQuery({
    variables: {
      args: {
        locale,
        limit: PAGE_SIZE,
        offset: 0,
        ...(isSearching ? { query: debounced } : {}),
      },
    },
    skip: isDummy || usePreview,
    notifyOnNetworkStatusChange: true,
  });

  // Reset page counter on filter change so a fresh result set starts
  // at the top. `debounced` (search) + `usePreview` are deliberate
  // re-run triggers (not read in the body): when the filter changes we
  // want pagination reset to the first page.
  // biome-ignore lint/correctness/useExhaustiveDependencies: debounced + usePreview are intentional reset triggers, not unused deps
  useEffect(() => {
    setVisibleCount(PAGE_SIZE);
  }, [debounced, usePreview]);

  // ─── Item projection ─────────────────────────────────────────
  const feedItems = useMemo(
    () =>
      (listData?.visitorNewsList.items ?? [])
        .filter((p): p is NonNullable<typeof p> => !!p)
        .map(toMockShape),
    [listData],
  );
  const previewItems = usePreview
    ? (previewFeed ?? [])
        .filter((p): p is Record<string, unknown> => !!p && typeof p === "object")
        .map(toMockShape)
    : [];

  const matchesQuery = useCallback(
    (n: MockNewsItem) =>
      n.title.toLowerCase().includes(debounced.toLowerCase()) ||
      n.excerpt.toLowerCase().includes(debounced.toLowerCase()),
    [debounced],
  );

  const fullList: MockNewsItem[] = isDummy
    ? isSearching
      ? getMockNewsItems(tDemo).filter(matchesQuery)
      : getMockNewsItems(tDemo)
    : usePreview
      ? isSearching
        ? previewItems.filter(matchesQuery)
        : previewItems
      : feedItems;

  // Real mode: Apollo cache holds everything across `fetchMore`
  // calls. Preview/dummy slice up to `visibleCount`.
  const items = usePreview || isDummy ? fullList.slice(0, visibleCount) : fullList;

  // ─── Load-more ────────────────────────────────────────────────
  const hasMore = useMemo(() => {
    if (isDummy || usePreview) return visibleCount < fullList.length;
    return listData?.visitorNewsList.meta.hasNextPage ?? false;
  }, [isDummy, usePreview, visibleCount, fullList.length, listData]);

  const [loadingMore, setLoadingMore] = useState(false);
  const loadMore = useCallback(async () => {
    if (!hasMore || loadingMore) return;
    if (isDummy || usePreview) {
      setVisibleCount((c) => c + PAGE_SIZE);
      return;
    }
    setLoadingMore(true);
    try {
      await fetchMore({
        variables: {
          args: {
            locale,
            limit: PAGE_SIZE,
            offset: listData?.visitorNewsList.items.length ?? 0,
            ...(isSearching ? { query: debounced } : {}),
          },
        },
        updateQuery: (prev, { fetchMoreResult }) => {
          if (!fetchMoreResult) return prev;
          // Dedup by id when merging pages. The BE's `offset` cursor
          // can return overlapping items in two scenarios:
          //   1. A new post lands between requests — every item
          //      shifts by one in the next page, so the boundary
          //      row appears in both prev + fetchMore.
          //   2. React StrictMode (dev only) fires `fetchMore`
          //      twice; the same page lands twice without dedup.
          // Either case surfaces as React's "two children with the
          // same key" warning. Keep prev's instance when there's a
          // collision so Apollo's cache references stay stable.
          const seen = new Set<string>();
          const merged: typeof prev.visitorNewsList.items = [];
          for (const item of [
            ...prev.visitorNewsList.items,
            ...fetchMoreResult.visitorNewsList.items,
          ]) {
            // Raw `NewsPost` shape carries Mongo's `_id` — the
            // local projection that the rendered list uses (`item.id`)
            // is computed downstream from this same field. Dedup on
            // `_id` so we match what Apollo's normalisation keys on.
            if (item && !seen.has(item._id)) {
              seen.add(item._id);
              merged.push(item);
            }
          }
          return {
            ...prev,
            visitorNewsList: {
              ...fetchMoreResult.visitorNewsList,
              items: merged,
            },
          };
        },
      });
    } finally {
      setLoadingMore(false);
    }
  }, [
    hasMore,
    loadingMore,
    isDummy,
    usePreview,
    isSearching,
    debounced,
    locale,
    fetchMore,
    listData,
  ]);

  const viewportRef = useScrollRestore("news");
  const handleScroll = useCallback(
    (e: React.UIEvent<HTMLDivElement>) => {
      const el = e.currentTarget;
      const remaining = el.scrollHeight - el.clientHeight - el.scrollTop;
      if (remaining < LOAD_MORE_THRESHOLD) void loadMore();
    },
    [loadMore],
  );

  const hasAny = fullList.length > 0 || isSearching;
  const firstLoad = !isDummy && !usePreview && listLoading && items.length === 0;

  // Surface BE errors (rare — auth issues) as the empty state copy.
  // Apollo's `errorPolicy: 'all'` lets data + errors coexist; we treat
  // a non-empty list as "render anyway".
  if (listError && items.length === 0) {
    return (
      <div className="flex flex-1 flex-col items-center justify-center gap-3 px-6 py-12 text-center">
        <p className="text-sm text-wx-fg-muted">{t("emptyTitle")}</p>
      </div>
    );
  }

  return (
    <ScrollArea className="flex-1" viewportRef={viewportRef} onScroll={handleScroll}>
      {hasAny && (
        <StickySearchHeader
          value={query}
          onChange={setQuery}
          placeholder={t("searchPlaceholder")}
        />
      )}
      <div className="flex flex-col gap-3 px-4 pt-4 pb-6">
        {firstLoad ? (
          Array.from({ length: 3 }).map((_, idx) => (
            // biome-ignore lint/suspicious/noArrayIndexKey: static placeholder list
            <div key={idx} className="overflow-hidden rounded-wx-lg bg-wx-bg-elevated">
              <Skeleton className="aspect-[16/10] w-full rounded-none" />
              <div className="space-y-2 px-5 py-4">
                <Skeleton className="h-3 w-3/4" />
                <Skeleton className="h-3 w-1/2" />
                <Skeleton className="mt-1 h-2 w-1/3" />
              </div>
            </div>
          ))
        ) : items.length === 0 ? (
          <div className="flex flex-1 flex-col items-center justify-center gap-3 px-6 py-12 text-center">
            <div className="flex h-14 w-14 items-center justify-center rounded-full bg-wx-bg-elevated text-wx-fg-muted">
              <Icon icon={Megaphone} size={28} />
            </div>
            <p className="text-base font-semibold text-wx-fg">
              {isSearching ? t("noResults") : t("emptyTitle")}
            </p>
            {!isSearching && <p className="text-sm text-wx-fg-muted">{t("emptyBody")}</p>}
          </div>
        ) : (
          <>
            {items.map((item, idx) => (
              <NewsCardButton
                key={item.id}
                item={item}
                locale={locale}
                delay={idx < PAGE_SIZE ? idx * 0.04 : 0}
                onClick={() => onOpenArticle(item.id)}
              />
            ))}
            {loadingMore && (
              <div className="flex justify-center py-3">
                <Skeleton className="h-3 w-24" />
              </div>
            )}
          </>
        )}
      </div>
    </ScrollArea>
  );
}

/** Project a raw `NewsPost` (or prefetched operator-side row) into
 *  the in-memory shape the news cards consume. Tags / cover / edit-
 *  badge fields all resolve through this single mapper. */
function toMockShape(raw: Record<string, unknown>, idx = 0): MockNewsItem {
  const mediaCover = (raw.coverImageUrl as Record<string, unknown> | undefined)?.url;
  const externalCover = raw.externalCoverImageUrl;
  const cover =
    typeof mediaCover === "string"
      ? mediaCover
      : typeof externalCover === "string"
        ? externalCover
        : null;

  const toChips = (raw_: unknown): { slug: string; label: string }[] | undefined =>
    Array.isArray(raw_)
      ? (raw_ as unknown[])
          .map((t) => {
            if (!t || typeof t !== "object") return null;
            const slug = (t as { slug?: unknown }).slug;
            const label = (t as { label?: unknown }).label;
            if (typeof slug !== "string" || typeof label !== "string") {
              return null;
            }
            return { slug, label };
          })
          .filter((t): t is { slug: string; label: string } => !!t)
      : undefined;

  const tags = toChips(raw.tags);
  // BE localizes the embedded category/tag labels against the visitor's
  // locale (the list query passes it), so these arrive already-translated.
  const categories = toChips(raw.categories);

  // Authors (operator byline) → `{ _id, name, photo: { url } }`, the
  // shape `MockNewsItem.authors` + `AuthorAvatars` both accept.
  const authors = Array.isArray(raw.authors)
    ? (raw.authors as unknown[])
        .map((a) => {
          if (!a || typeof a !== "object") return null;
          const name = (a as { name?: unknown }).name;
          if (typeof name !== "string") return null;
          const aid = (a as { _id?: unknown })._id;
          const url = (a as { photo?: { url?: unknown } }).photo?.url;
          return {
            _id: String(aid ?? name),
            name,
            photo: { url: typeof url === "string" ? url : "" },
          };
        })
        .filter((a): a is { _id: string; name: string; photo: { url: string } } => !!a)
    : undefined;

  return {
    id: String(raw._id ?? raw.id ?? `news-${idx}`),
    title: typeof raw.title === "string" ? raw.title : "",
    excerpt: typeof raw.excerpt === "string" ? raw.excerpt : "",
    publishedAt: typeof raw.publishedAt === "string" ? raw.publishedAt : new Date().toISOString(),
    coverGradient: ["#1e1f21", "#121314"],
    ...(cover ? { coverImageUrl: cover } : {}),
    ...(typeof raw.upstreamUpdatedAt === "string"
      ? { upstreamUpdatedAt: raw.upstreamUpdatedAt }
      : {}),
    ...(tags && tags.length > 0 ? { tags } : {}),
    ...(categories && categories.length > 0 ? { categories } : {}),
    ...(authors && authors.length > 0 ? { authors } : {}),
    reactionCounts: (raw.reactionCounts as Record<string, number> | null | undefined) ?? null,
  };
}

/**
 * Stock 300 ms debounce — keeps the BE search load proportional to
 * the visitor's typing cadence, not their keystroke rate.
 */
function useDebounced(value: string, delay: number): string {
  const [debounced, setDebounced] = useState(value);
  useEffect(() => {
    const t = setTimeout(() => setDebounced(value), delay);
    return () => clearTimeout(t);
  }, [value, delay]);
  return debounced;
}

function NewsCardButton({
  item,
  locale,
  delay,
  onClick,
}: {
  item: MockNewsItem;
  locale: string;
  delay: number;
  onClick: () => void;
}) {
  const t = useTranslations("news");
  const cats = item.categories ?? (item.category ? [item.category] : []);
  const authorChips = toAuthorChips(item.authors);
  return (
    <motion.button
      type="button"
      onClick={onClick}
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      whileHover={{ y: -2 }}
      whileTap={{ scale: 0.985 }}
      transition={{ duration: 0.2, delay }}
      className={cn(
        "block w-full shrink-0 overflow-hidden rounded-wx-lg bg-wx-bg-elevated text-left",
        "transition-colors hover:bg-wx-bg-elevated-2",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-wx-primary focus-visible:ring-offset-2 focus-visible:ring-offset-wx-bg",
      )}
    >
      <div
        className="aspect-[16/10] w-full bg-cover bg-center"
        style={
          item.coverImageUrl
            ? { backgroundImage: `url(${item.coverImageUrl})` }
            : {
                background: `linear-gradient(135deg, ${item.coverGradient[0]}, ${item.coverGradient[1]})`,
              }
        }
        aria-hidden="true"
      />
      <div className="px-5 py-4">
        {(cats.length > 0 || authorChips != null) && (
          // Categories on the left, author byline avatars on the right.
          <div className="mb-1.5 flex items-center justify-between gap-2">
            <div className="flex min-w-0 flex-wrap gap-1.5">
              {cats.slice(0, 2).map((cat) => (
                <span
                  key={cat.slug}
                  className="text-[10px] font-semibold uppercase tracking-wide text-wx-primary"
                >
                  {cat.label}
                </span>
              ))}
            </div>
            <AuthorAvatars authors={authorChips} className="shrink-0" />
          </div>
        )}
        <CardTitle className="text-sm">{item.title}</CardTitle>
        {item.excerpt && <CardSubtitle className="mt-1 text-xs">{item.excerpt}</CardSubtitle>}
        <p className="mt-2 flex items-center gap-2 text-xs text-wx-fg-subtle">
          <span>
            {new Date(item.publishedAt).toLocaleDateString(locale, {
              month: "short",
              day: "numeric",
              year: "numeric",
            })}
          </span>
          {isNewsPostEdited(item) && item.upstreamUpdatedAt && (
            <span
              className="rounded-full bg-wx-bg-elevated px-1.5 py-0.5 text-[10px] font-medium text-wx-fg-muted"
              title={new Date(item.upstreamUpdatedAt).toLocaleString(locale)}
            >
              {t("editedAt", { when: formatNewsEditedAgo(item.upstreamUpdatedAt) })}
            </span>
          )}
        </p>
        {item.tags && item.tags.length > 0 && (
          <div className="mt-2.5 flex flex-wrap gap-1">
            {item.tags.slice(0, 4).map((tag) => (
              <span
                key={tag.slug}
                className="rounded-full bg-wx-bg-elevated px-2 py-0.5 text-[10px] font-medium text-wx-fg-muted"
              >
                {tag.label}
              </span>
            ))}
          </div>
        )}
      </div>
    </motion.button>
  );
}
