/**
 * Overlapping author-avatar stack — shared by the help list, help
 * folder drill-in, help search results, and (once news posts carry
 * authors) the news feed. Renders up to `max` avatars; falls back to an
 * initial when a photo is missing. Returns `null` when there are none.
 */

export interface AuthorChip {
  id: string;
  name: string;
  photoUrl: string | null;
}

/** Normalise an authors array (demo or BE — both `{ _id, name, photo:
 *  { url } }`) to the avatar-chip shape. `undefined` when empty/invalid. */
export function toAuthorChips(raw: unknown): AuthorChip[] | undefined {
  if (!Array.isArray(raw)) return undefined;
  const chips = raw
    .map((a): AuthorChip | null => {
      if (!a || typeof a !== "object") return null;
      const name = (a as { name?: unknown }).name;
      if (typeof name !== "string") return null;
      const id = (a as { _id?: unknown; id?: unknown })._id ?? (a as { id?: unknown }).id;
      const url = (a as { photo?: { url?: unknown } }).photo?.url;
      return {
        id: String(id ?? name),
        name,
        photoUrl: typeof url === "string" ? url : null,
      };
    })
    .filter((a): a is AuthorChip => !!a);
  return chips.length > 0 ? chips : undefined;
}

export function AuthorAvatars({
  authors,
  max = 3,
  className,
}: {
  authors: AuthorChip[] | null | undefined;
  max?: number;
  className?: string;
}) {
  if (!authors || authors.length === 0) return null;
  return (
    <span className={`flex items-center -space-x-1.5 ${className ?? ""}`}>
      {authors.slice(0, max).map((author) =>
        author.photoUrl ? (
          // biome-ignore lint/performance/noImgElement: widget is framework-agnostic (no next/image in the embed)
          <img
            key={author.id}
            src={author.photoUrl}
            alt={author.name}
            title={author.name}
            className="h-5 w-5 rounded-full border border-wx-bg object-cover"
          />
        ) : (
          <span
            key={author.id}
            title={author.name}
            className="flex h-5 w-5 items-center justify-center rounded-full border border-wx-bg bg-wx-bg-elevated-2 text-[9px] font-semibold text-wx-fg-muted"
          >
            {author.name.charAt(0).toUpperCase()}
          </span>
        ),
      )}
    </span>
  );
}
