/**
 * Demo-mode news content. Surfaced when the widget runs with
 * `forceDummyData` / `mode=demo` — see `lib/use-widget-env.tsx`.
 *
 * Structure (id, date, gradient) lives here; the translatable text
 * (title, excerpt) comes from the `demo.news.*` next-intl namespace
 * (both locales), read via `t.raw()`. See `dummy/translator.ts`.
 */

import { authorsFor, type DemoAuthor, type DemoAuthorKey } from "./authors";
import type { DemoTranslator } from "./translator";

export interface MockNewsItem {
  id: string;
  title: string;
  excerpt: string;
  /** Post byline — one or more authors. */
  authors?: DemoAuthor[];
  /** Section the post belongs to (e.g. Product, Company). Rendered as
   *  an eyebrow above the title on the detail view. */
  category?: { slug: string; label: string };
  /** Full markdown body shown on the article detail view. Same shape
   *  as the help articles' `contentMarkdown`. Optional because the
   *  feed-card mapping (`toMockShape` in the news tab) doesn't carry a
   *  body — only the demo detail builder (`getMockNewsItems`) sets it. */
  contentMarkdown?: string;
  publishedAt: string;
  coverGradient: [string, string];
  /** Operator-supplied cover image — wins over the gradient when set. */
  coverImageUrl?: string;
  /** External-source edit timestamp. Only set for posts pulled in from
   *  RSS / webhook sources whose `fieldMap.updatedAt` resolved. The
   *  feed cards + article view derive the "edited Xh ago" badge when
   *  this is meaningfully newer than `publishedAt`. */
  upstreamUpdatedAt?: string | null;
  /** Operator taxonomy chips — rendered on cards + the detail view. */
  tags?: { slug: string; label: string }[];
  /** Section(s) the post belongs to — rendered as chips on the feed
   *  card (the singular `category` above is the detail-view eyebrow). */
  categories?: { slug: string; label: string }[];
  /** Sparse `{ [slotIndex]: count }` map. Surfaced on cards as a
   *  read-only chip strip via `ReactionCountsStrip`. */
  reactionCounts?: Record<string, number> | null;
}

/** Locale-independent fields, defined once. Cover images use seeded
 *  `picsum.photos` URLs (same approach as the demo conversation media)
 *  so the feed + article hero show real photography in the showcase. */
/** `tagSlugs` map to `news.tags.<slug>` labels and `categorySlug` to
 *  `news.categories.<slug>` in the demo i18n bundle; `authorIds`
 *  reference `DEMO_AUTHORS`. */
type NewsStruct = Pick<MockNewsItem, "id" | "publishedAt" | "coverGradient" | "coverImageUrl"> & {
  authorIds: DemoAuthorKey[];
  categorySlug: string;
  tagSlugs: string[];
};

