/**
 * Build the demo news feed from the active `demo` translator. Returns a
 * fresh array each call — wrap in `useMemo` at the call site if the
 * reference needs to stay stable across renders.
 */
export function getMockNewsItems(t: DemoTranslator): MockNewsItem[] {
  return NEWS_STRUCT.map(({ tagSlugs, authorIds, categorySlug, ...s }) => ({
    ...s,
    title: t.raw(`news.${s.id}.title`) as string,
    excerpt: t.raw(`news.${s.id}.excerpt`) as string,
    contentMarkdown: t.raw(`news.${s.id}.body`) as string,
    authors: authorsFor(authorIds),
    category: { slug: categorySlug, label: t.raw(`news.categories.${categorySlug}`) as string },
    tags: tagSlugs.map((slug) => ({ slug, label: t.raw(`news.tags.${slug}`) as string })),
  }));
}
