"use client";

import { cn } from "@/lib/utils";

/**
 * Brand-tinted shimmer placeholder. Used while async data is in
 * flight (chat history, help categories, news feed). The animation
 * is a soft pulse on `bg-wx-bg-elevated` — reads as chrome on any
 * widget surface (light bubble, primary bubble, gradient hero).
 *
 * Compose at the call site to match the shape of the eventual
 * content (e.g. round avatars, line-height bars). Keeps the skeleton
 * footprint zero-cost when not in use; just plain divs with one
 * `animate-pulse` class.
 */
export function Skeleton({ className, ...props }: React.HTMLAttributes<HTMLDivElement>) {
  return (
    <div
      data-slot="skeleton"
      className={cn("animate-pulse rounded-wx-sm bg-wx-bg-elevated", className)}
      {...props}
    />
  );
}
